<script setup lang="ts">
import{onMounted,reactive,ref}from'vue';import{useCartStore}from'@/stores/cart';import{api}from'@/services/api';const cart=useCartStore();const coupon=ref('');const gateways=ref<any[]>([]);const checkout=reactive({email:'',name:'',phone:'',gatewayKey:'sandbox',notes:''});const result=ref<any>(null);async function apply(){await cart.refresh(coupon.value)}async function buy(){if(!cart.token)return;result.value=await api(`/api/public/commerce/carts/${cart.token}/checkout`,{method:'POST',body:JSON.stringify({...checkout,couponCode:coupon.value,billing:{},shipping:{},returnUrl:location.origin+'/cart',cancelUrl:location.origin+'/cart',idempotencyKey:crypto.randomUUID()})});cart.reset()}const money=(v:number,c='USD')=>new Intl.NumberFormat('es-HN',{style:'currency',currency:c}).format(v||0);onMounted(async()=>{await cart.ensure();gateways.value=await api('/api/public/commerce/gateways')});
</script>

<template>
<main class="content-section"><div class="section-heading"><div><span class="eyebrow">CHECKOUT</span><h1 class="text-5xl font-black">Su carrito</h1></div><RouterLink to="/store" class="button secondary">Continuar comprando</RouterLink></div><div v-if="result" class="panel text-center"><span class="status-pill ok">Compra procesada</span><h2 class="mt-4 text-3xl font-black">Orden {{result.orderNumber}}</h2><p class="mt-2">{{result.message}}</p><RouterLink v-if="result.orderToken" :to="`/saas/claim?order=${result.orderNumber}&token=${result.orderToken}`" class="button mt-5">Ver licencias y descargas</RouterLink></div><div v-else class="grid gap-8 lg:grid-cols-[1fr_420px]"><section class="panel"><div v-if="!cart.cart?.items.length" class="empty"><h2>El carrito está vacío</h2><RouterLink to="/store" class="button mt-4">Explorar tienda</RouterLink></div><article v-for="i in cart.cart?.items" :key="i.id" class="cart-line"><div><b>{{i.name}}</b><small>{{money(i.unitPrice,i.currency)}} por unidad</small></div><input :value="i.quantity" type="number" min="0" @change="cart.update(i.id,Number(($event.target as HTMLInputElement).value))"><strong>{{money(i.lineTotal,i.currency)}}</strong></article></section><aside class="panel h-fit"><h2 class="text-2xl font-bold">Resumen</h2><div class="mt-5 space-y-3"><div class="flex justify-between"><span>Subtotal</span><b>{{money(cart.cart?.subtotal||0,cart.cart?.currency)}}</b></div><div class="flex justify-between text-emerald-700"><span>Descuento</span><b>-{{money(cart.cart?.discountTotal||0,cart.cart?.currency)}}</b></div><div class="flex justify-between border-t pt-4 text-xl"><span>Total</span><b>{{money(cart.cart?.total||0,cart.cart?.currency)}}</b></div></div><div class="mt-5 flex"><input v-model="coupon" class="flex-1" placeholder="Cupón"><button class="button secondary" @click="apply">Aplicar</button></div><form class="form-stack mt-6" @submit.prevent="buy"><label>Nombre<input v-model="checkout.name" required></label><label>Correo<input v-model="checkout.email" type="email" required></label><label>Teléfono<input v-model="checkout.phone"></label><label>Método de pago<select v-model="checkout.gatewayKey"><option v-for="g in gateways" :key="g.key" :value="g.key">{{g.name}}</option></select></label><button class="button full" :disabled="!cart.cart?.items.length">Finalizar compra</button></form></aside></div></main></template>
